body.script:
(function(){
'use strict';
function $(id){return document.getElementById(id);}
function lsGet(key){try{return localStorage.getItem(key);}catch(e){return null;}}
function lsSet(key,value){try{localStorage.setItem(key,value);}catch(e){}}
function setNbsp(el){el.innerHTML='&nbsp;';}
function getData(el,key){return el.getAttribute('data-'+key)||'';}
function lower(text){return (text||'').toLowerCase();}

var PW='GG123';
var INJEX_PW='GG456';
var INJEX_SEARCH_TRIGGER='injex';
var AUTH_KEY='gg_auth';
var INJEX_KEY='gg_injex';
var unlocked=false;
var reduceMotion=window.matchMedia&&window.matchMedia('(prefers-reduced-motion: reduce)').matches;
var toastTimer;
function showToast(msg){
  var t=$('toast');
  t.textContent=msg;
  t.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer=setTimeout(function(){t.classList.remove('show');},2200);
}
function injexUnlocked(){return lsGet(INJEX_KEY)==='1';}
var injexCard=document.querySelector('.card[data-secret="true"]');

function applyInjexVisibility(){
  if(!injexCard)return;
  if(injexUnlocked()){injexCard.removeAttribute('data-secret');injexCard.style.display='';}
}

function unlock(){
  if(unlocked)return;
  unlocked=true;
  $('pw').style.display='none';
  $('site').style.display='block';
  applyInjexVisibility();
  if(!reduceMotion){
    initStars();
    initShootingStars();
  }else{
    $('cvs').style.display='none';
  }
  initImgLoaded();
  initFilter();
}

var pwIn=$('pw-in'),pwErr=$('pw-err'),pwInner=document.querySelector('.pw-inner');
function tryPW(){
  if(pwIn.value===PW){lsSet(AUTH_KEY,'1');unlock();}
  else{
    pwErr.textContent='Wrong code \u2014 try again';
    pwIn.value='';
    pwInner.classList.remove('pw-shake');
    void pwInner.offsetWidth;
    pwInner.classList.add('pw-shake');
    setTimeout(function(){setNbsp(pwErr);},2200);
    setTimeout(function(){pwInner.classList.remove('pw-shake');},420);
  }
}
$('pw-go').onclick=tryPW;
pwIn.addEventListener('keydown',function(e){if(e.key==='Enter')tryPW();});

function initImgLoaded(){
  var thumbs=document.querySelectorAll('.th');
  function markLoaded(th){th.classList.add('loaded');}
  for(var i=0;i<thumbs.length;i++){
    var th=thumbs[i];
    var img=th.querySelector('img');
    if(!img){markLoaded(th);continue;}
    if(img.complete){markLoaded(th);}
    else{
      (function(currTh,currImg){
        currImg.addEventListener('load',function(){markLoaded(currTh);});
        currImg.addEventListener('error',function(){markLoaded(currTh);});
      })(th,img);
    }
  }
}

function initStars(){var cv=document.getElementById('cvs'),ctx=cv.getContext('2d'),stars=[];function resize(){cv.width=window.innerWidth;cv.height=window.innerHeight;stars=[];for(var i=0;i<180;i++)stars.push({x:Math.random()*cv.width,y:Math.random()*cv.height,r:Math.random()*0.8+0.1,a:Math.random()*0.45+0.05,sp:Math.random()*0.0012+0.0003,ph:Math.random()*Math.PI*2,c:0});for(var i=0;i<60;i++)stars.push({x:Math.random()*cv.width,y:Math.random()*cv.height,r:Math.random()*1.4+0.5,a:Math.random()*0.5+0.1,sp:Math.random()*0.0008+0.0002,ph:Math.random()*Math.PI*2,c:Math.floor(Math.random()*3)+1});}window.addEventListener('resize',resize);resize();var cols=['rgba(255,255,255,','rgba(168,200,255,','rgba(200,168,255,','rgba(168,240,255,'];function frame(t){ctx.clearRect(0,0,cv.width,cv.height);for(var i=0;i<stars.length;i++){var s=stars[i];var a=s.a*(0.4+0.6*Math.sin(t*s.sp*60+s.ph));ctx.beginPath();ctx.arc(s.x,s.y,s.r,0,Math.PI*2);ctx.fillStyle=cols[s.c]+a+')';ctx.fill();}requestAnimationFrame(frame);}requestAnimationFrame(frame);}
function initShootingStars(){var cols=['rgba(255,255,255,.9),rgba(168,85,247,.45)','rgba(56,189,248,.9),rgba(168,85,247,.3)','rgba(244,114,182,.8),rgba(109,40,217,.3)'];function spawn(){var el=document.createElement('div');var sx=Math.random()*window.innerWidth,sy=Math.random()*window.innerHeight*0.5,len=70+Math.random()*150,dur=400+Math.random()*600,ang=15+Math.random()*35,dist=280+Math.random()*420,c=cols[Math.floor(Math.random()*cols.length)];el.style.cssText='position:fixed;left:'+sx+'px;top:'+sy+'px;width:'+len+'px;height:1.5px;border-radius:1px;pointer-events:none;z-index:0;transform-origin:left center;background:linear-gradient(90deg,'+c+',transparent)';document.body.appendChild(el);el.animate([{transform:'rotate('+ang+'deg) translateX(0)',opacity:1},{transform:'rotate('+ang+'deg) translateX('+dist+'px)',opacity:0}],{duration:dur,easing:'ease-in',fill:'forwards'}).onfinish=function(){el.remove();};}(function loop(){spawn();setTimeout(loop,1200+Math.random()*3500);})();}

function getTags(c){var t=c.getAttribute('data-tags')||'';return t.split(',').map(function(s){return s.trim();}).filter(Boolean);}

var injexModal=$('injex-modal');
var injexIn=$('injex-in');
var injexErr=$('injex-err');
var injexPendingCard=null;
function openInjexModal(card){
  injexPendingCard=card;
  injexModal.classList.add('open');
  injexIn.value='';
  setNbsp(injexErr);
  setTimeout(function(){injexIn.focus();},60);
}
function closeInjexModal(){injexModal.classList.remove('open');injexPendingCard=null;}
function tryInjex(){
  if(injexIn.value===INJEX_PW){
    var cardToOpen=injexPendingCard;
    lsSet(INJEX_KEY,'1');closeInjexModal();
    if(injexCard){injexCard.removeAttribute('data-secret');injexCard.style.display='';if(typeof runFilter==='function')runFilter();}
    showToast('\uD83D\uDD12 Injex unlocked \u2014 it\'s yours forever!');
    openGame(cardToOpen);
  } else {
    injexErr.textContent='Wrong code \u2014 access denied';injexIn.value='';
    injexIn.style.borderColor='#ef4444';injexIn.style.boxShadow='0 0 0 3px rgba(239,68,68,0.2)';
    setTimeout(function(){setNbsp(injexErr);injexIn.style.borderColor='';injexIn.style.boxShadow='';},2000);
  }
}
$('injex-go').onclick=tryInjex;
$('injex-cancel').onclick=closeInjexModal;
injexIn.addEventListener('keydown',function(e){if(e.key==='Enter')tryInjex();if(e.key==='Escape')closeInjexModal();});

var runFilter;
function initFilter(){
  var allCards=Array.prototype.slice.call(document.querySelectorAll('#game-grid .card'));
  var normalCards=[],secretCards=[];
  for(var i=0;i<allCards.length;i++){
    if(allCards[i].getAttribute('data-secret')==='true')secretCards.push(allCards[i]);
    else normalCards.push(allCards[i]);
  }

  for(var i=0;i<allCards.length;i++){
    (function(card){
      var isSecret=card.getAttribute('data-secret')==='true';
      function handlePlay(){if(isSecret&&!injexUnlocked()){openInjexModal(card);}else{openGame(card);}}
      card.setAttribute('tabindex','0');
      card.setAttribute('role','button');
      card.setAttribute('aria-label','Open '+getData(card,'name'));
      card.addEventListener('click',handlePlay);
      card.addEventListener('keydown',function(e){
        if(e.key==='Enter'||e.key===' '){
          e.preventDefault();
          handlePlay();
        }
      });
      var btn=card.querySelector('.cbtn');
      if(btn)btn.addEventListener('click',function(e){e.stopPropagation();handlePlay();});
    })(allCards[i]);
  }

  var sqEl=$('sq'),sqClear=$('sq-clear'),noresEl=$('nores'),activeCat='all';
  $('gc').textContent='Showing '+normalCards.length+' of '+normalCards.length+' games';
  function shouldShowCard(card,query){
    var tags=getTags(card);
    var catOk=activeCat==='all'||tags.indexOf(activeCat)!==-1;
    var nameOk=!query||lower(getData(card,'name')).indexOf(query)!==-1;
    return catOk&&nameOk;
  }

  var filterTimer;
  sqEl.addEventListener('input',function(){
    sqClear.classList.toggle('visible',sqEl.value.length>0);
    clearTimeout(filterTimer);
    filterTimer=setTimeout(runFilter,75);
  });
  sqClear.onclick=function(){sqEl.value='';sqClear.classList.remove('visible');sqEl.focus();runFilter();};
  var pills=document.querySelectorAll('#cat-bar .cp');
  for(var i=0;i<pills.length;i++){pills[i].addEventListener('click',function(){for(var j=0;j<pills.length;j++)pills[j].classList.remove('on');this.classList.add('on');activeCat=this.getAttribute('data-c');sqEl.value='';sqClear.classList.remove('visible');runFilter();});}

  runFilter=function(){
    var q=lower(sqEl.value).trim();
    var shown=0;
    for(var i=0;i<normalCards.length;i++){
      var c=normalCards[i];
      var show=shouldShowCard(c,q);
      c.style.display=show?'':'none';
      if(show)shown++;
    }
    for(var i=0;i<secretCards.length;i++){
      var s=secretCards[i];
      var alreadyUnlocked=!s.getAttribute('data-secret');
      var show=false;
      if(alreadyUnlocked){show=shouldShowCard(s,q);}
      else{show=q===INJEX_SEARCH_TRIGGER;}
      s.style.display=show?'':'none';
      if(show)shown++;
    }
    noresEl.style.display=shown?'none':'block';
    $('gc').textContent='Showing '+shown+' of '+normalCards.length+' games';
  };
  runFilter();
}

var player=$('player'),gframe=$('gframe'),ptitle=$('ptitle'),pbarCats=$('pbar-cats');
var catColors={Action:'color:#c026d3;border-color:rgba(192,38,211,0.4);background:rgba(192,38,211,0.1)',Arcade:'color:#0ea5e9;border-color:rgba(14,165,233,0.4);background:rgba(14,165,233,0.1)',Puzzle:'color:#7c3aed;border-color:rgba(124,58,237,0.4);background:rgba(124,58,237,0.1)',Strategy:'color:#10b981;border-color:rgba(16,185,129,0.4);background:rgba(16,185,129,0.1)',Adventure:'color:#a855f7;border-color:rgba(168,85,247,0.4);background:rgba(168,85,247,0.1)',Sports:'color:#22c55e;border-color:rgba(34,197,94,0.4);background:rgba(34,197,94,0.1)',Horror:'color:#ef4444;border-color:rgba(239,68,68,0.4);background:rgba(239,68,68,0.1)',Pokemon:'color:#facc15;border-color:rgba(250,204,21,0.4);background:rgba(250,204,21,0.1)',Other:'color:#f59e0b;border-color:rgba(245,158,11,0.4);background:rgba(245,158,11,0.1)'};
function renderPlayerChips(tags){
  pbarCats.innerHTML='';
  for(var i=0;i<tags.length;i++){
    var span=document.createElement('span');
    span.className='pbar-cat-chip';
    span.textContent=tags[i];
    span.style.cssText=(catColors[tags[i]]||'color:var(--muted);border-color:var(--border)')+';font-size:.55rem;font-weight:600;letter-spacing:1px;padding:2px 8px;border-radius:99px;border:1px solid';
    pbarCats.appendChild(span);
  }
}
function openGame(card){
  ptitle.textContent=getData(card,'name').toUpperCase();
  var tags=getTags(card);
  renderPlayerChips(tags);
  var BASE='https://cdn.jsdelivr.net/gh/SurgeColt999/GalaxyGames@main/';
  gframe.src=BASE+getData(card,'file');
  player.classList.add('open');
  document.body.style.overflow='hidden';
}
function closePlayer(){gframe.src='about:blank';player.classList.remove('open');document.body.style.overflow='';}
$('pb-close').onclick=closePlayer;
$('pb-reload').onclick=function(){var s=gframe.src;gframe.src='about:blank';setTimeout(function(){gframe.src=s;},80);showToast('Reloading game...');};
$('pb-fs').onclick=function(){var el=gframe,fn=el.requestFullscreen||el.webkitRequestFullscreen||el.mozRequestFullScreen||el.msRequestFullscreen;if(fn)fn.call(el);};
document.addEventListener('keydown',function(e){if(e.key==='Escape'){if(injexModal.classList.contains('open')){closeInjexModal();}else if(player.classList.contains('open')){closePlayer();}}});
$('nav-home').onclick=function(){this.classList.add('active');};

if(lsGet(AUTH_KEY)==='1')unlock();
})();
